        elif char == ')':
            paren_count -= 1
            if paren_count < 0:
                raise ETLError(
                    "BAD_EXPR",
                    "ETL_ERROR: unbalanced parentheses in expression",
                    path
                )

    if paren_count != 0:
        raise ETLError(
